import (
	context "context"
	fernclient "github.com/pagination-uri-path/fern/client"
	option "github.com/pagination-uri-path/fern/option"
)

client := fernclient.NewClient(
	option.WithToken(
		"<YOUR_AUTH_TOKEN>",
	),
)
response, err := client.Users.ListWithPathPagination(
	context.TODO(),
)

